<?php
// Create (or return) a synthetic course shell.
//
// Idempotency is by `idnumber` (a synth-stable identifier we control).
// The function also ensures a "Synthetic / Not for production" category
// exists and places the course there unless an explicit category id is given.

namespace local_neurollm\external;

defined('MOODLE_INTERNAL') || die();

global $CFG;
require_once($CFG->dirroot . '/course/lib.php');
// `core_course_category` is autoloaded in Moodle 4+; no `coursecatlib.php` include needed.

use core_external\external_api;
use core_external\external_function_parameters;
use core_external\external_single_structure;
use core_external\external_value;
use stdClass;

class create_course extends external_api {

    public static function execute_parameters(): external_function_parameters {
        return new external_function_parameters([
            'fullname'    => new external_value(PARAM_TEXT, 'Course full name'),
            'shortname'   => new external_value(PARAM_TEXT, 'Course shortname (must be globally unique in Moodle)'),
            'idnumber'    => new external_value(PARAM_TEXT, 'Stable synth idnumber (e.g. synth-naive-bayes-abc123)', VALUE_DEFAULT, ''),
            'summary'     => new external_value(PARAM_RAW, 'HTML course summary', VALUE_DEFAULT, ''),
            'numsections' => new external_value(PARAM_INT, 'Number of sections (weeks)', VALUE_DEFAULT, 1),
            'category_id' => new external_value(PARAM_INT, 'Target category id; 0 = use/create the synthetic category', VALUE_DEFAULT, 0),
            'category_name' => new external_value(PARAM_TEXT, 'Category name to use when category_id=0', VALUE_DEFAULT, 'Synthetic / Not for production'),
        ]);
    }

    public static function execute_returns(): external_single_structure {
        return new external_single_structure([
            'course_id'   => new external_value(PARAM_INT, 'Moodle course id'),
            'shortname'   => new external_value(PARAM_TEXT, 'Course shortname'),
            'idnumber'    => new external_value(PARAM_TEXT, 'Course idnumber'),
            'category_id' => new external_value(PARAM_INT, 'Resolved category id'),
            'created'     => new external_value(PARAM_BOOL, 'True if newly created, false if reused'),
            'view_url'    => new external_value(PARAM_URL, 'Browser URL to view the course'),
        ]);
    }

    public static function execute(
        string $fullname,
        string $shortname,
        string $idnumber = '',
        string $summary = '',
        int $numsections = 1,
        int $categoryid = 0,
        string $categoryname = 'Synthetic / Not for production'
    ): array {
        global $DB, $CFG;

        $params = self::validate_parameters(self::execute_parameters(), [
            'fullname'      => $fullname,
            'shortname'     => $shortname,
            'idnumber'      => $idnumber,
            'summary'       => $summary,
            'numsections'   => $numsections,
            'category_id'   => $categoryid,
            'category_name' => $categoryname,
        ]);

        self::validate_context(\context_system::instance());
        require_capability('moodle/course:create', \context_system::instance());

        // Resolve category (create the synthetic category lazily if needed).
        $catid = (int) $params['category_id'];
        if ($catid <= 0) {
            $existing = $DB->get_record('course_categories', ['idnumber' => 'neuro_synth']);
            if ($existing) {
                $catid = (int) $existing->id;
            } else {
                $cat = \core_course_category::create([
                    'name'        => $params['category_name'],
                    'idnumber'    => 'neuro_synth',
                    'description' => 'Synthetic courses generated by neuro-moodle-llm. Not pedagogically reviewed.',
                    'descriptionformat' => FORMAT_HTML,
                ]);
                $catid = (int) $cat->id;
            }
        }

        // Idempotency: prefer idnumber match, fall back to shortname.
        $existing = null;
        if ($params['idnumber'] !== '') {
            $existing = $DB->get_record('course', ['idnumber' => $params['idnumber']]);
        }
        if (!$existing && $params['shortname'] !== '') {
            $existing = $DB->get_record('course', ['shortname' => $params['shortname']]);
        }

        if ($existing) {
            return [
                'course_id'   => (int) $existing->id,
                'shortname'   => $existing->shortname,
                'idnumber'    => $existing->idnumber,
                'category_id' => (int) $existing->category,
                'created'     => false,
                'view_url'    => (new \moodle_url('/course/view.php', ['id' => $existing->id]))->out(false),
            ];
        }

        $data = new stdClass();
        $data->fullname        = $params['fullname'];
        $data->shortname       = $params['shortname'];
        $data->idnumber        = $params['idnumber'];
        $data->category        = $catid;
        $data->summary         = $params['summary'];
        $data->summaryformat   = FORMAT_HTML;
        $data->format          = 'topics';
        $data->numsections     = max(1, (int) $params['numsections']);
        $data->visible         = 1;
        $data->showgrades      = 1;
        $data->newsitems       = 0;
        $data->startdate       = time();
        $data->enablecompletion = 1;

        $course = create_course($data);

        return [
            'course_id'   => (int) $course->id,
            'shortname'   => $course->shortname,
            'idnumber'    => (string) $course->idnumber,
            'category_id' => (int) $course->category,
            'created'     => true,
            'view_url'    => (new \moodle_url('/course/view.php', ['id' => $course->id]))->out(false),
        ];
    }
}
